INSERT INTO public.photos VALUES (23310, 'Calle de Alfonso I 1908', 'Foto: Aurelio Grasa. Vista de la confluencia de la calle de Alfonso I con el Coso Alto. Al fondo, el palacio de Sâ”œÃ­stago. Fuente: Archivo de Aurelio Grasa. Archivo Barboza Grasa (www.aureliograsa.es, www.barbozagrasa.es). Forma parte de un reportaje cedido a la revista Sombras Foto de la RSFZ en 2008.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65310300, -0.88197600, '0101000020E6100000B16B7BBB2539ECBFB2F50CE198D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31993760184.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31993760184.webp', 'https://www.flickr.com/photos/zaragozaantigua/31993760184/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23311, 'Calle de Alfonso I 1908', 'Foto: Aurelio Grasa. Arco conmemorativo del Centenario de los Sitios, colocado a la entrada de la calle de Alfonso I en 1908. Fuente: Archivo Barboza-Grasa, a travâ”œÂ®s de Heraldo de Aragâ”œâ”‚n.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65315100, -0.88207300, '0101000020E61000004FE8F527F139ECBFC32CB4739AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32505799200.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32505799200.webp', 'https://www.flickr.com/photos/zaragozaantigua/32505799200/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24932, 'Tren del Parque 1972', 'El Tren del Parque de Primo de Rivera junto a su estaciâ”œâ”‚n a la entrada del paseo de los Plâ”œÃ­tanos, actual de Manuel Azaâ”œâ–’a. En activo desde finales de los aâ”œâ–’os 20, se trata de un tractor de recreo con apariencia de locomotora que tira dos vagones de pasajeros, cuyo diseâ”œâ–’o se ha mantenido con fidelidad al original de comienzos del siglo XX, si bien los vehâ”œÂ¡culos se han ido sustituyendo, en funciâ”œâ”‚n de su vida â”œâ•‘til. El de la imagen es de los aâ”œâ–’os 60.', 1972, 1972, 1972, 'Anos 70', 'UNIVERSIDAD', 41.63633900, -0.89787600, '0101000020E61000001FA0FB7266BBECBFAD156D8E73D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15239008624.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15239008624.webp', 'https://www.flickr.com/photos/zaragozaantigua/15239008624/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20867, 'El Batallador aâ”œâ–’os 20', 'AHPZ. Estudio Coyne. (SF). "Parque Primo de Rivera. Monumento al Rey Alfonso I el Batallador." Obra de Josâ”œÂ® Bueno, esta escultura fue realizada con motivo del aniversario 800 de la conquista cristiana de la ciudad de Saraqusta, en 1118.', 1920, 1920, 1929, 'Anos 20', 'UNIVERSIDAD', 41.63359100, -0.89335200, '0101000020E61000003F1EFAEE5696ECBF1D05888219D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14754143588.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14754143588.webp', 'https://www.flickr.com/photos/zaragozaantigua/14754143588/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23314, 'Calle de Alfonso I c.1895', 'Inâ”œÂ®dita imagen capturada a nivel de calle en el Coso Alto y centrada en el arranque de la calle de Alfonso I hasta el desemboque, al fondo, en la plaza del Pilar. A la izquierda, imagen parcial de la antigua casa solariega de los marqueses de Tosos, que en 1833 fue vendida a un particular como inmueble del nâ”¬â•‘ 7 del Coso Alto. Reformada varias veces, cuando en la dâ”œÂ®cada de los 60 fue abierta la calle Alfonso I, este edificio mantuvo su alineamiento original, el de la imagen, hasta que en 1902 fue remodelado profundamente, ya como nâ”¬â•‘ 17 del Coso: realineado, se levantâ”œâ”‚ una nueva planta, se homologaron las alturas de sus bajos a las de los comercios que caracterizaban la calle, se le achaflanâ”œâ”‚ la esquina, y se le dio un estilo mâ”œÃ­s profusamente decorativo, con balconadas y rejerâ”œÂ¡as mâ”œÃ­s "modernas". A la derecha, inmueble del nâ”¬â•‘ 1 de Alfonso I y del nâ”¬â•‘ 23 del Coso Alto, construido en 1869 con proyecto del arquitecto Juan Antonio Atienza, tras la apertura de la nueva calle de Alfonso I, para el confitero Eusebio Molins, que en sus bajos habilitâ”œâ”‚ la "Confiterâ”œÂ¡a y reposterâ”œÂ¡a El Buen Gusto", con el caracterâ”œÂ¡stico chaflâ”œÃ­n de los edificios de la burguesa calle, donde se daba salida a las pastas, dulces, bombones, caramelos y chocolates producidos en la golosa fâ”œÃ­brica "La Gemela del Buen Gusto", sita junto a la antigua carretera de Valencia. Este edificio tambiâ”œÂ®n fue remodelado en 1902, con proyecto de Fernando de Yarza, dejâ”œÃ­ndole su actual aspecto modernista.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65314600, -0.88207100, '0101000020E6100000220038F6EC39ECBFB1C1C2499AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48066993067.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48066993067.webp', 'https://www.flickr.com/photos/zaragozaantigua/48066993067/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23498, 'Palacio de Sâ”œÃ­stago 1861', 'Vista del Palacio de Sâ”œÃ­stago en el Coso Alto, construida por don Artal de Alagâ”œâ”‚n, III conde de Sâ”œÃ­stago y virrey de Aragâ”œâ”‚n. Desde 1843, Joaquâ”œÂ¡n Mâ”¬Â¬ Fernâ”œÃ­ndez de Câ”œâ”‚rdoba, â”œâ•‘ltimo conde de Sâ”œÃ­stago, arrendâ”œâ”‚ parte del palacio al Casino Principal de Zaragoza. A la derecha e inmediata, la casa del Marquâ”œÂ®s de Campo Franco y a continuaciâ”œâ”‚n la casa de la condesa de Fuentes. Fuente: Mariano Jâ”œâ•‘dez y Ortiz. â”œÃ¼lbum de Andrâ”œÂ®s Martâ”œÂ¡n e Ipâ”œÃ­s. Colecciâ”œâ”‚n Mariano Martâ”œÂ¡n Casalderrey. Libro Primeros tiempos de la fotografâ”œÂ¡a en Zaragoza.', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.65272400, -0.88186000, '0101000020E610000063D174763238ECBF3BA8C4758CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710512790.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710512790.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710512790/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23508, 'Arco de San Roque c.1932', 'Imagen del Arco de San Roque desde la plazuela de San Roque, como confluencia de las calles Palomeque (izquierda), y Valenzuela (derecha), con el Coso y el Hotel Oriente de telâ”œâ”‚n de fondo. Con motivo de la peste de Marsella del aâ”œâ–’o 1721, sobre este arco se instalâ”œâ”‚ una imagen de San Roque y su perro, ya que segâ”œâ•‘n la santa madre iglesia catâ”œâ”‚lica este es el santo protector en caso de darse esta y otras epidemias, sobre las que tendrâ”œÂ¡a mano (de santo). Al perro no se le han reconocido otros poderes que el del acompaâ”œâ–’amiento y la contemplaciâ”œâ”‚n, y los resultados efectivos de la religiosa protecciâ”œâ”‚n aâ”œâ•‘n no han sido demostrados de forma objetiva. Este arco daba acceso a la antigua Morerâ”œÂ¡a de la ciudad, o gueto de los musulmanes hasta su expulsiâ”œâ”‚n en 1610. En 1942 el arco y las viviendas inmediatas fueron piqueteadas para abrir una calle mâ”œÃ­s cristiana y espaciosa, ampliar la plaza, y elevar nuevos y altos edificios de bancos y seguros con que flanquear a la barroca iglesia del antiguo Convento de Santo Tomâ”œÃ­s de Villanueva.', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.65321000, -0.88286500, '0101000020E6100000AA0EB9196E40ECBFC8B5A1629CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16556750848.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16556750848.webp', 'https://www.flickr.com/photos/zaragozaantigua/16556750848/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23511, 'Plaza de San Roque c.1930', 'Imagen de la portada de la barroca iglesia de Santo Tomâ”œÃ­s de Villanueva, tambiâ”œÂ®n llamada de la Manterâ”œÂ¡a, en la plaza de San Roque. A la derecha queda la calle de Palomeque, antigua de la Manterâ”œÂ¡a. A la izquierda, restos del antiguo colegio de Santo Tomâ”œÃ­s y San Jorge. La imagen se ha capturado junto al arco de San Roque. Fuente visual: Archivo fotogrâ”œÃ­fico Josâ”œÂ® Galiay Saraâ”œâ–’ana (DARA-AHPZ).', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65317200, -0.88306700, '0101000020E61000009CA8A5B91542ECBFDA54DD239BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22523155070.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22523155070.webp', 'https://www.flickr.com/photos/zaragozaantigua/22523155070/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23513, 'Plaza de San Roque c.1936', 'Imagen capturada bajo el Arco de San Roque, de la irregular y antigua plaza de San Roque, como espacio de confluencia del final de la calle Palomeque (a la derecha), el arranque de la calle de Valenzuela (antigua de la Morerâ”œÂ¡a Cerrada), hacia la izquierda, y el acceso desde el Coso Alto por el propio Arco. Justo a la derecha, fuera de plano, quedaba la barroca fachada de la iglesia de la Manterâ”œÂ¡a, antigua de Santo Tomâ”œÃ­s de Villanueva del convento de los Agustinos Observantes. Hacia la izquierda, por donde se encamina el grupo de personas, y torciendo la esquina, se llegaba al nâ”¬â•‘ 12 de la Morerâ”œÂ¡a, donde residiera la familia del joven Francisco Goya desde 1736 hasta 1757, aproximadamente. Al comienzo de los aâ”œâ–’os 40, el Arco de San Roque serâ”œÂ¡a derribado, y despuâ”œÂ®s le tocarâ”œÂ¡a el turno al resto de edificios de la imagen, para reordenar la zona de forma adecuada. Sic transit gloria Urbis. Fuente visual: Joaquâ”œÂ¡n Gil Marraco (Catâ”œÃ­logo Exposiciâ”œâ”‚n grupo "Calle a Calle", Colegio de Arquitectos de Zaragoza, abril/mayo de 1980). Amable aportaciâ”œâ”‚n de Josâ”œÂ® Luis Cintora.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65317200, -0.88306700, '0101000020E61000009CA8A5B91542ECBFDA54DD239BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24567643425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24567643425.webp', 'https://www.flickr.com/photos/zaragozaantigua/24567643425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23517, 'Calle de Palomeque c. 1935', 'Desde la relativa altura de una balconera en el antiguo nâ”¬â•‘ 29 de la calle de Palomeque, un vistazo integral de esa calle desde la inmediata plaza de San Roque, y hasta su arranque en la plaza de Santâ”œÃ­ngel, al fondo, y la antigua calle del Azoque. Justo a la espalda del fotâ”œâ”‚grafo perduraba el arco de San Roque, nacido a esa advocaciâ”œâ”‚n como inane profilaxis a la peste marsellesa de principios de la dâ”œÂ®cada de los aâ”œâ–’os veinte, en la diez y ocho centuria. A la izquierda, reconocible esquina de la barroca fâ”œÃ­brica en ladrillo de la iglesia de la Manterâ”œÂ¡a, del antiguo colegio de Santo Tomâ”œÃ­s de Villanueva. De esta iglesia el vial tomâ”œâ”‚ su nombre hasta que fue redenominado en homenaje al arzobispo que desde entonces le da nombre. Fuente visual: Archivo Juan Mora (Archivo Municipal de Zaragoza).', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.65317200, -0.88306700, '0101000020E61000009CA8A5B91542ECBFDA54DD239BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28838648350.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28838648350.webp', 'https://www.flickr.com/photos/zaragozaantigua/28838648350/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23520, 'Gerardo Sancho 2002', 'Imagen del fotâ”œâ”‚grafo Gerardo Sancho Ramo (Navarrete del Râ”œÂ¡o, Teruel, 1911), tomada en 2002 en el hotel Alfonso I. Discâ”œÂ¡pulo de Miguel Marâ”œÂ¡n Chivite, trabajâ”œâ”‚ en Heraldo de Aragâ”œâ”‚n, Amanecer, El Noticiero y Europa Press. Tras realizar decenas de miles de fotografâ”œÂ¡as de Zaragoza, que atesora el Archivo Municipal, se retirâ”œâ”‚ en 1981. Falleciâ”œâ”‚ en Valencia el 14 de diciembre de 2006. Fuente: Heraldo de Aragâ”œâ”‚n.', 2002, 2002, 2002, 'Siglo XXI', 'CENTRO', 41.65326300, -0.88223400, '0101000020E61000009C6A2DCC423BECBFEB573A1F9ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31879664240.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31879664240.webp', 'https://www.flickr.com/photos/zaragozaantigua/31879664240/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23956, 'P.â”¬â•‘ de la Independencia 1931', 'Tarde del 14 de abril de 1931. Celebraciâ”œâ”‚n, en el paseo de la Independencia, de la proclamaciâ”œâ”‚n de la Segunda Repâ”œâ•‘blica Espaâ”œâ–’ola. Al fondo, la plaza de la Constituciâ”œâ”‚n. A la izquierda, la calle del Cinco de Marzo. Las "Mariannes" y la gran bandera de la Agrupaciâ”œâ”‚n Republicana del Arrabal, sobre una furgoneta de plataforma abierta Daimler-Mercedes U 2 T. Fuente: Heraldo de Aragâ”œâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65128100, -0.88210400, '0101000020E61000001077F52A323AECBFCAC0012D5DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14813401299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14813401299.webp', 'https://www.flickr.com/photos/zaragozaantigua/14813401299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23961, '&quot;El Ibâ”œâ”‚n&quot; 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 05/01/1974. El 12.10.1932 se inaugurâ”œâ”‚ el "Frontâ”œâ”‚n Emendek" en la calle del Cinco de Marzo. Menos de dos aâ”œâ–’os despuâ”œÂ®s, y hasta loa aâ”œâ–’os 50, pasarâ”œÂ¡a a ser el gigantesco Cinema Frontâ”œâ”‚n, con 1.250 localidades, y luego albergarâ”œÂ¡a la sala de Fiestas Râ”œÂ¡o Club. En abril de 1963 se volviâ”œâ”‚ a utilizar como frontâ”œâ”‚n de pelota vasca, hasta que en 1973, se instalâ”œâ”‚ una pista de hielo (â”¬Â½El Ibâ”œâ”‚nâ”¬â•—), concebida para la prâ”œÃ­ctica multitudinaria del patinaje desde una perspectiva exclusivamente lâ”œâ•‘dica. Pero se derritiâ”œâ”‚ enseguida.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65206400, -0.88280600, '0101000020E61000006CCD565EF23FECBF117349D576D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14936712681.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14936712681.webp', 'https://www.flickr.com/photos/zaragozaantigua/14936712681/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24021, 'Coso Alto 1917', 'Abril de 1917. Comitiva del entierro del torero zaragozano Florentino Ballesteros (1893-1917), a su paso por el Coso Alto en direcciâ”œâ”‚n a la plaza de la Constituciâ”œâ”‚n. En la parte superior y tras el palacio de Sâ”œÃ­stago, el reciâ”œÂ®n levantado edificio del Banco de Aragâ”œâ”‚n, con un andamio. Despuâ”œÂ®s, el cine Ena Victoria, donde la antigua casa de la Condesa de Fuentes. Mâ”œÃ­s allâ”œÃ­, el Arco de San Roque.', 1917, 1917, 1917, 'Anos 10', 'CENTRO', 41.65309200, -0.88215500, '0101000020E61000009817601F9D3AECBFBEA3C68498D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24721067012.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24721067012.webp', 'https://www.flickr.com/photos/zaragozaantigua/24721067012/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24028, 'Quiosco de la Mâ”œâ•‘sica 1916', 'Jura de bandera en el paseo de la Independencia de Zaragoza, el 5 de marzo de 1916. Aspecto del Quiosco de la Mâ”œâ•‘sica durante la misa de campaâ”œâ–’a. Al fondo, la plaza de Espaâ”œâ–’a. A la derecha, el convento de Jesâ”œâ•‘s. En primer plano, militares feligreses. Fuente: Archivo ABC.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.65115700, -0.88192200, '0101000020E6100000E5EE737CB438ECBFDEC7D11C59D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24841740425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24841740425.webp', 'https://www.flickr.com/photos/zaragozaantigua/24841740425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24031, 'P.â”¬â•‘ de la Independencia 1931', 'Foto: Miguel Marâ”œÂ¡n Chivite. Celebraciâ”œâ”‚n de la proclamaciâ”œâ”‚n de la Segunda Repâ”œâ•‘blica, el 14 de abril de 1931. Un grupo de mujeres sobre un carro portan un retrato del fundador del PSOE, Pablo Iglesias. Al fondo, comercios en los porches del paseo Independencia, como la Camiserâ”œÂ¡a Josâ”œÂ® Barril, en el nâ”œâ•‘mero 10. Fuente: Heraldo de Aragâ”œâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65101200, -0.88222200, '0101000020E61000008BF9B9A1293BECBFDBA6785C54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26299814620.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26299814620.webp', 'https://www.flickr.com/photos/zaragozaantigua/26299814620/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24045, 'Tarzâ”œÃ­n 1959', 'Imagen parcial, capturada en el segundo tramo del paseo de la Independencia, del callejeo publicitario realizado por el holandâ”œÂ®s "Circo Espaâ”œâ–’ol" venido al calor de las fiestas de octubre. Un elefante mâ”œÃ­s asiâ”œÃ­tico que africano es cabalgado por un actor que representa al personaje de Tarzâ”œÃ­n, que conduce sin Cheeta, ni Jane. Fuente visual: www.todocoleccion.net/', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.65101200, -0.88222200, '0101000020E61000008BF9B9A1293BECBFDBA6785C54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30975296975.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30975296975.webp', 'https://www.flickr.com/photos/zaragozaantigua/30975296975/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24069, 'Coso Alto 1974', 'Imagen del Coso alto capturada durante las fiestas mayores de la ciudad. Los personajes del "Verrugâ”œâ”‚n" (izquierda) y el "Forano" (derecha), integrantes de la comparsa de cabezudos, encorren a la chiquillerâ”œÂ¡a delante del acceso al cine Coso, que proyecta "El calzonazos", domâ”œÂ®stica comedia ligera de Mariano Ozores protanizada por Paco Martâ”œÂ¡nez Soria y Florinda Chico. Fuente visual: foto Antonio â”œÃ¬â”œâ–’iguez Valls, en www.todocoleccion.net/', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65328400, -0.88257400, '0101000020E6100000D09849D40B3EECBF028063CF9ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34050601131.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34050601131.webp', 'https://www.flickr.com/photos/zaragozaantigua/34050601131/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24095, 'Calle del Cinco de Marzo 1936', 'Imagen capturada en el interior del gran Frontâ”œâ”‚n Cinema militarizado para acoger a algunos de los 1.200 requetâ”œÂ®s navarros llegados a la ciudad para consolidar y reforzar la defensa nacionalista de la ciudad ante las ofensivas republicanas para tratar de tomarla, durante las primeras semanas de la guerra. Causalmente, la nueva Corporaciâ”œâ”‚n Municipal redenominarâ”œÂ¡a esta calle poco despuâ”œÂ®s como homenaje a esta organizaciâ”œâ”‚n paramilitar carlista.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65212800, -0.88275700, '0101000020E61000001215AA9B8B3FECBF276728EE78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49669039592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49669039592.webp', 'https://www.flickr.com/photos/zaragozaantigua/49669039592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24243, 'Pâ”¬â•‘ Independencia 1950', 'Bipolar imagen capturada en el antiguo Paseo de la Independencia nâ”¬â•‘ 12. A la derecha, escaparate del estudio de Miguel Marâ”œÂ¡n Chivite, artâ”œÂ¡culos fotogrâ”œÃ­ficos "Para fotos perfectas". A la izquierda, cartel del encuentro de fâ”œâ•‘tbol entre el Arenas S.D. y el C.D. Logroâ”œâ–’â”œÂ®s, correspondiente a la jornada 19 de la Liga de la Tercera Divisiâ”œâ”‚n, en el Campo de Deportes de San Josâ”œÂ®. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.65101200, -0.88222200, '0101000020E61000008BF9B9A1293BECBFDBA6785C54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30207865902.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30207865902.webp', 'https://www.flickr.com/photos/zaragozaantigua/30207865902/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24247, 'Gustavo Freudenthal 1917', 'Gustavo Freudenthal (1869-1948), prusiano de Hannover, abriâ”œâ”‚ un estudio fotogrâ”œÃ­fico en el Coso 31 de Zaragoza en 1906. Entre 1917 y 1930, se instalâ”œâ”‚ en el â”œÃ­tico del Banco de Aragâ”œâ”‚n en el Coso 42, frente a la calle de Alfonso I. De 1914 a 1941, fue Câ”œâ”‚nsul Honorario de Alemania. Publicâ”œâ”‚ sus fotos en ABC, La Ilustraciâ”œâ”‚n Espaâ”œâ–’ola y Americana o Heraldo de Aragâ”œâ”‚n. En la imagen, Freudenthal (al fondo a la derecha), posa con unos amigos en su reciâ”œÂ®n estrenado â”œÃ­tico. Mâ”œÃ­s allâ”œÃ­, despunta la torre de San Pablo.', 1917, 1917, 1917, 'Anos 10', 'CENTRO', 41.65296600, -0.88223400, '0101000020E61000009C6A2DCC423BECBF31B3CF6394D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32960238336.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32960238336.webp', 'https://www.flickr.com/photos/zaragozaantigua/32960238336/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24382, 'Colegio Escolapias c.1930', '"Patio del antiguo convento de los escolapios" (sic). Imagen del antiguo patio del colegio de Santo Tomâ”œÃ­s de Villanueva y San Jorge, de los PP. Agustinos Observantes, sito en la plazuela de la Manterâ”œÂ¡a. Asociado a la fâ”œÃ­brica de la iglesia y demâ”œÃ­s dependencias colegiales de esta Orden, fue realizado a finales del siglo XVII en limpias formas barrocas, y ladrillo como material fundamental. Desde 1883, en que fue adquirido por las MM. Escolapias para habilitarlo como colegio, fue objeto de varias intervenciones. La mâ”œÃ­s radical estuvo asociada con el derribo del arco de San Roque y la ampliaciâ”œâ”‚n de la plaza del mismo nombre, el ensanchamiento de la antigua calle de la Morerâ”œÂ¡a Cerrada, y el despeje de la plaza de Salamero, a finales de los aâ”œâ–’os 40 del pasado siglo. El nuevo edificio colegial resultante, diseâ”œâ–’ado por Teodoro Râ”œÂ¡os, ya no contaba con este patio. Sic transit gloria mundi. Fuente visual: Archivo Moreno, Fototeca del Patrimonio Histâ”œâ”‚rico (www.mcu.es/)', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65301200, -0.88323900, '0101000020E6100000E3A7716F7E43ECBFA1F2AFE595D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22618247892.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22618247892.webp', 'https://www.flickr.com/photos/zaragozaantigua/22618247892/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24448, 'P.â”¬â•‘ de la Independencia 1966', 'Tras la piqueta, los nuevos materiales constructivos aceleran el proceso de levantar el armazâ”œâ”‚n metâ”œÃ­lico del nuevo edificio del nâ”¬â•‘ 8 del paseo de la Independencia. Su revestimiento acristalado serâ”œÃ­ tambiâ”œÂ®n seâ”œâ–’a de identidad de los nuevos tiempos. Su funciâ”œâ”‚n: unos grandes almacenes. A su izquierda, el nâ”¬â•‘ 10 tambiâ”œÂ®n serâ”œÃ­ piquetado y construido bajo parâ”œÃ­metros constructivos similares, aunque los cristales del exterior tendrâ”œÃ­n un teâ”œâ–’ido un poco mâ”œÃ­s oscuro, en lâ”œÂ¡nea corporativa con la entidad bancaria que lo posee. A su derecha, la calle Requetâ”œÂ® Aragonâ”œÂ®s, que permite una visual parcial de la Iglesia de Santiago el Mayor. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65127200, -0.88217800, '0101000020E6100000A305685BCD3AECBF776682E15CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15217618591.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15217618591.webp', 'https://www.flickr.com/photos/zaragozaantigua/15217618591/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24525, 'Calle del Requetâ”œÂ® Aragonâ”œÂ®s c.1960', 'Imagen centrada en la fachada del antiguo cafâ”œÂ® Nikâ”œÂ®, con proyecto de los arquitectos Regino y Josâ”œÂ® Borobio, abierto en 1940 en el local comercial del nâ”¬â•‘ 10 de la calle del Requetâ”œÂ® Aragonâ”œÂ®s (antiguo nâ”¬â•‘ 7 de la calle del 5 de Marzo), flanqueado por el Frontâ”œâ”‚n Cinema (izquierda) y un patio de ingreso a la Diputaciâ”œâ”‚n Provincial (a la derecha, fuera de plano). Este establecimiento ha quedado incorporado a la historia de la cultura zaragozana de mediados del siglo XX por servir de sede, primero, de la Peâ”œâ–’a Nikâ”œÂ®, que en los aâ”œâ–’os cuarenta reuniâ”œâ”‚ una destacada pluralidad de personalidades del mundillo cultural local de la â”œÂ®poca. En la dâ”œÂ®cada de los cincuenta el Nikâ”œÂ® se convirtiâ”œâ”‚ en el domicilio social de la Oficina Poâ”œÂ®tica Internacional por la iniciativa del poeta Miguel Labordeta, que tuvo de "oficinistas" a algunos de los mâ”œÃ­s floridos representantes de la cultura zaragozana de la â”œÂ®poca, con poetas, pintores, novelistas, cineastas, dramaturgos, actores, crâ”œÂ¡ticos, cientâ”œÂ¡ficos, activistas culturales, diletantes y entusiastas de la cultura en general. Este antiguo cafâ”œÂ® Nikâ”œÂ® fue clausurado en 1969. Fuente visual: javierbarreiro.wordpress.com', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65185700, -0.88286300, '0101000020E61000007C26FBE76940ECBF9755D80C70D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41071417531.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41071417531.webp', 'https://www.flickr.com/photos/zaragozaantigua/41071417531/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24528, 'P.â”¬â•‘ de la Independencia 1975', 'Nocturna imagen capturada en el paseo de la Independencia durante las inciertas navidades del aâ”œâ–’o 1975, las primeras tras la reciente muerte del dictador Franco. Lucen esplendorosos los neones con motivos tradicionales de la festividad impostada al natural solsticio de invierno, destacando por su tamaâ”œâ–’o los luminosos adosados a la fachada de los grandes almacenes Galerâ”œÂ¡as Preciados. Por la autopista ruge la automovilâ”œÂ¡stica marabunta, paseo arriba, paseo abajo.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.65115800, -0.88191000, '0101000020E6100000D47D00529B38ECBFAF43352559D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47961471822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47961471822.webp', 'https://www.flickr.com/photos/zaragozaantigua/47961471822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25055, 'Cardenal y Alcalde 1961', 'Ayuntamiento de Zaragoza/Foto Lozano. Setiembre 1961. Con motivo del V Congreso Eucarâ”œÂ¡stico Nacional, el zaragozano Cardenal de Sevilla, Josâ”œÂ® Marâ”œÂ¡a Bueno Monreal y el Alcalde de Zaragoza entre 1954 y 1966, Luis Gâ”œâ”‚mez Laguna, desfilan en coche descubierto por la ciudad, con nocturnidad y disparidad de actitudes. La chaqueta blanca del munâ”œÂ¡cipe era parte del uniforme del partido gobernante: el Movimiento Nacional. El Mercedes estâ”œÃ­ pasando ante el nâ”œâ•‘mero 9 del Coso Alto, a la altura de Calzados Segarra.', 1961, 1961, 1961, 'Anos 60', 'CENTRO', 41.65341800, -0.88290500, '0101000020E610000038328FFCC140ECBF124F7633A3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14758105399.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14758105399.webp', 'https://www.flickr.com/photos/zaragozaantigua/14758105399/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25089, 'Coso Alto 1908', 'Paso de la carroza de Alfonso XIII por el Coso Alto, a la altura del palacio de Sâ”œÃ­stago, con el Gran Cafâ”œÂ® de Parâ”œÂ¡s en sus bajos. Poco despuâ”œÂ®s la comitiva ingresarâ”œÃ­ en la calle Alfonso I. Fuente visual: revista "Ilustraciâ”œâ”‚n militar. Ejâ”œÂ®rcito y Marina".', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65291000, -0.88188000, '0101000020E61000002AE3DF675C38ECBF9D9D0C8E92D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32431683413.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32431683413.webp', 'https://www.flickr.com/photos/zaragozaantigua/32431683413/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25113, 'Alegorâ”œÂ¡a de Zaragoza 1889', 'Ars Catalogi/DPZ "Alegorâ”œÂ¡a de Zaragoza", de Alejandro Ferrant. En la planta "noble" del Palacio de los Condes de Sâ”œÃ­stago se encuentran los salones VIP. El arquitecto Ricardo Magdalena, responsable de recuperar el edificio, encargâ”œâ”‚ en 1889 al pintor Alejandro Ferrant Fischermans una alegorâ”œÂ¡a de Zaragoza para ilustrar el abovedado techo del salâ”œâ”‚n principal. Y ahâ”œÂ¡ sobrevuela la estancia esta joven llamada Zaragoza, simbolizada como madre de insignes personas representadas a los lados; como resistente antiafrancesada a su pesar; como lugar cristianamente empoderado tras la Venida de la Virgen en carne mortal sobre columnamâ”œâ”‚vil; y como amante melâ”œâ”‚mana de la jota que le estâ”œÃ­ echando un terrenal jotero, justo debajo de la nube en la que aposenta sus reales. Una Zaragoza convencional, confesional, sumante de tâ”œâ”‚picos tradicionalistas.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65272400, -0.88186000, '0101000020E610000063D174763238ECBF3BA8C4758CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14946140527.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14946140527.webp', 'https://www.flickr.com/photos/zaragozaantigua/14946140527/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25126, 'Toma de Zaragoza 1809', '"Siâ”œÂ¿ge et Prise de Saragosse- Guerre d''Espagne (1807-1814)" : [estampe] â”œÃ«diteur : Paris chez la V.ve Châ”œÂ®reau Mde d''Estampes Rue St Jacques Nâ”¬â–‘ 10. En un entorno irreal, se pretende representar el momento en que las tropas imperiales francesas irrumpen en la ciudad durante el Segundo Sitio, en febrero de 1809, tras la ruptura de las lâ”œÂ¡neas de defensa, mientras los defensores huyen y se precipitan en una iglesia, que podrâ”œÂ¡a ser desde la del convento de San Ildefonso, hasta la de los Invâ”œÃ­lidos de Parâ”œÂ¡s. Fuente visual: catalogue.bnf.fr/ark:/12148/cb415145946.', 1809, 1809, 1809, 'Siglo XIX', 'CENTRO', 41.65230400, -0.88452800, '0101000020E610000064AE0CAA0D4EECBF66868DB27ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16334501623.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16334501623.webp', 'https://www.flickr.com/photos/zaragozaantigua/16334501623/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25166, 'Calle del Serâ”œâ”‚n aâ”œâ–’os 30', 'Acuarela de Ambrosio del Ruste identificada como "Calle del Serâ”œâ”‚n". Este callejâ”œâ”‚n partâ”œÂ¡a de la calle de Azoque, en las inmediaciones de la de Ramâ”œâ”‚n Pignatelli. Desapareciâ”œâ”‚ con la apertura de la Vâ”œÂ¡a Imperial. Fuente: Lâ”œÃ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65304700, -0.88352100, '0101000020E6100000F0880AD5CD45ECBF1EE0490B97D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32399494456.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32399494456.webp', 'https://www.flickr.com/photos/zaragozaantigua/32399494456/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25188, 'Plaza de Miguel Salamero 1980', 'Dibujo centrado en una vista panorâ”œÃ­mica orientada hacia el noreste de la plaza de Miguel Salamero (antigua de Santa Fe). De izquierda a derecha, el ingreso a la calle del Azoque, la iglesia parroquial de Santiago el Mayor, la mole descontextualizada del Edificio Salamero, el colegio de las Escolapias y la anexa iglesia de la Manterâ”œÂ¡a, la torre angular del edificio del Banco de Aragâ”œâ”‚n, y el desemboque de la calle del Cinco de Marzo. En el centro de la plaza, aspecto de su arbolada isleta central establecida tras la construcciâ”œâ”‚n del aparcamiento habilitado en su subterrâ”œÃ­neo. Este fue el aspecto de la plaza hasta su mâ”œÃ­s reciente reforma, que le confiriâ”œâ”‚ su actual aspecto a finales del mes de marzo del presente aâ”œâ–’o 2023.', 1980, 1980, 1980, 'Anos 80', 'CENTRO', 41.65229600, -0.88423800, '0101000020E6100000A12C7C7DAD4BECBFE3A7716F7ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53268033853.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53268033853.webp', 'https://www.flickr.com/photos/zaragozaantigua/53268033853/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25277, 'Cine Rex 1955', 'Cine propiedad de la empresa Zaragoza Urbana S.A., situado en la Calle de Requetâ”œÂ® Aragonâ”œÂ®s nâ”¬â•‘ 5, fue diseâ”œâ–’ado por los arquitectos Josâ”œÂ® de Yarza y Teodoro Râ”œÂ¡os. Se inaugurâ”œâ”‚ en mayo de 1954 con la hollywoodiense cinta de cine fantâ”œÃ­stico "La tâ”œâ•‘nica sagrada", siendo la primera sala de la ciudad que incorporâ”œâ”‚ el novedoso sistema de proyecciâ”œâ”‚n cinemascope. Fue reformado en 1966, y en 1994 fue reconvertido en multicines, con tres espacios donde antes habâ”œÂ¡a uno, denominados "Palafox-Las Salas". En la imagen, aspecto exterior de la entrada al cine desde Requetâ”œÂ® Aragonâ”œÂ®s en el verano de 1955, cuando se proyectaba la mediocre cinta norteamericana "Lâ”œÂ¡nea secreta". Fuente visual: Foto Heraldo.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65174900, -0.88300800, '0101000020E61000005E6743FE9941ECBFB119E0826CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15020029406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15020029406.webp', 'https://www.flickr.com/photos/zaragozaantigua/15020029406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25287, 'Sara Montiel 1957', 'Archivo Municipal. Gerardo Sancho Ramo. Junio 1957. Imagen de Marâ”œÂ¡a Antonia Abad Fernâ”œÃ­ndez en su habitaciâ”œâ”‚n del hotel "Goya", durante la visita a la ciudad con motivo del estreno del filme "El â”œâ•‘ltimo cuplâ”œÂ®" (dirigida por Juan de Orduâ”œâ–’a). El recibimiento a la estrella fue apoteâ”œâ”‚sico, e incluso un joven cadete de la AGM de 19 aâ”œâ–’os de edad, llamado Juan Carlos, se acercâ”œâ”‚ al evento. Aunque en la imagen parece a punto de ponerse a hablar por el zapatâ”œâ”‚fono, sâ”œâ”‚lo estaba descansando los pies sentada sobre su cama, en el transcurso de una entrevista a los medios locales. Ella era asâ”œÂ¡ de natural.', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.65167100, -0.88286500, '0101000020E6100000AA0EB9196E40ECBF356090F469D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15595965147.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15595965147.webp', 'https://www.flickr.com/photos/zaragozaantigua/15595965147/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25300, 'P.â”¬â•‘ de la Independencia 1988', 'Foto Eduardo Zamarripa, 1988. Vista aâ”œÂ®rea del paseo de la Independencia de Zaragoza en 1988. Fuente: Aragâ”œâ”‚n desde el aire, Ministerio de Defensa, 1988.', 1988, 1988, 1988, 'Anos 80', 'CENTRO', 41.65106000, -0.88239400, '0101000020E6100000D3F88557923CECBFECDD1FEF55D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20293631286.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20293631286.webp', 'https://www.flickr.com/photos/zaragozaantigua/20293631286/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25320, 'Pasaje Palafox 1968', 'Foto: Josâ”œÂ® Antonio Duce. Pasaje Palafox, entre el paseo de la Independencia (a la espalda del fotâ”œâ”‚grafo) y la calle del Requetâ”œÂ® Aragonâ”œÂ®s. Fuente visual: www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65111600, -0.88275800, '0101000020E6100000290989B48D3FECBF80F3E2C457D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23427693650.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23427693650.webp', 'https://www.flickr.com/photos/zaragozaantigua/23427693650/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25360, 'P.â”¬â•‘ de la Independencia 1966', 'Luminosa imagen capturada en el paseo de la Independencia y centrada en el tramo comprendido entre las calles de Fray Diego Murillo (izquierda) y Requetâ”œÂ® Aragonâ”œÂ®s (derecha), durante la construcciâ”œâ”‚n de la moderna gran superficie comercial vertical destinada a la Sociedad Espaâ”œâ–’ola de Precios â”œÃœnicos, levantada sobre el solar dejado por el antiguo nâ”¬â•‘ 8 del paseo. A su lado perduraba aâ”œâ•‘n el antiguo nâ”¬â•‘ 10, edilicio vestigio de cuando aconteciera la ensoâ”œâ–’aciâ”œâ”‚n de que este vial acaso fuera durante un tiempo remedo de la parisina rue de Rivoli. La diferencia de escala (lâ”œÂ®ase aprovechamiento edificable) era demasiado golosa como para que fuera posible su perdurancia. Quedan imâ”œÃ­genes como esta, eso sâ”œÂ¡, recuerdo material y objetivo de esa ciudad imaginada que no fue posible porque no se quiso. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65101800, -0.88220200, '0101000020E6100000C5E74EB0FF3AECBFBD8DCD8E54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39819291185.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39819291185.webp', 'https://www.flickr.com/photos/zaragozaantigua/39819291185/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25363, 'P.â”¬â•‘ de la Independencia 1979', 'Imagen capturada en el paseo de la Independencia desalojado de su rutinaria ocupaciâ”œâ”‚n de vehâ”œÂ¡culos, y pateado por peatones de forma insâ”œâ”‚lita durante las primeras Fiestas del Pilar tras la recuperaciâ”œâ”‚n de la democracia municipal. Las programaciâ”œâ”‚n festiva inaugurâ”œâ”‚ la inclusiâ”œâ”‚n de este paseo como escenario al aire libre de mâ”œâ•‘sica en directo, en este caso de orquestas de verbena, donde la concurrencia se podâ”œÂ¡a dar un baile sin que nadie objetara nada. Otros actos de carâ”œÃ­cter abierto promovieron la participaciâ”œâ”‚n ciudadana como filosofâ”œÂ¡a que vertebrara unas fiestas que hasta entonces giraban en torno a ceremonias religiosas y actos de regodeo de la elite local. El cambio de paso intentâ”œâ”‚ ser zancadilleado por los poderes hegemâ”œâ”‚nicos hasta ese momento, como fue el caso del gobernador Civil Francisco Laâ”œÂ¡na Garcâ”œÂ¡a, elegido en tiempos predemocrâ”œÃ­ticos y todavâ”œÂ¡a en funciones. Fue el primer e improvisado paso hacia otro modelo de fiestas. La escena tiene lugar en el tramo del paseo flanqueado entre los grandes almacenes de Galerâ”œÂ¡as Preciados, a la izquierda, y el Sepu a la derecha, con la plaza de Aragâ”œâ”‚n al fondo.', 1979, 1979, 1979, 'Anos 70', 'CENTRO', 41.65115800, -0.88191000, '0101000020E6100000D47D00529B38ECBFAF43352559D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48793549668.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48793549668.webp', 'https://www.flickr.com/photos/zaragozaantigua/48793549668/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25494, 'Arco de San Roque aâ”œâ–’os 20', 'Archivo RUIZ VERNACCI. 1910-1950. "Arco de San Roque". Era el arco de mayor trâ”œÃ­fico humano de la ciudad, antiguo lugar de paso para el movimiento de personas y mercancâ”œÂ¡as entre el Coso alto, la plazuela de San Roque, la calle de Palomeque, la plazuela de Santâ”œÃ­ngel, y la calle del Azoque. Fue derribado en 1942 para ensanche al trâ”œÃ­fico rodado de la calle Tte. Cnel. Valenzuela. En la imagen, el arco visto desde el Coso, con una sastrerâ”œÂ¡a a su izquierda, una camiserâ”œÂ¡a a su derecha, y un seâ”œâ–’or fumando tabaco en medio, unos niâ”œâ–’os jugando... vida, en suma.', 1920, 1920, 1929, 'Anos 20', 'CENTRO', 41.65315400, -0.88265500, '0101000020E610000002D4D4B2B53EECBF34A0DE8C9AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14680155020.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14680155020.webp', 'https://www.flickr.com/photos/zaragozaantigua/14680155020/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25519, 'Calle de la Independencia 1903', 'Imagen centrada en el efâ”œÂ¡mero arco triunfal patrocinado por el Ayuntamiento de Zaragoza y erigido en la calle de la Independencia con motivo de la primera visita oficial del rey Alfonso XIII a la ciudad. Fue diseâ”œâ–’ado por el arquitecto municipal Ricardo Magdalena en el estilo neogâ”œâ”‚tico al gusto de la â”œÂ®poca con detalles ornamentales vegetales modernistas, destacando por su rareza el parabâ”œâ”‚lico arco central de inspâ”œÂ¼raciâ”œâ”‚n gaudiana. Al fondo, el tambiâ”œÂ®n efâ”œÂ¡mero arco de la Real Maestranza diseâ”œâ–’ado por el ingeniero Manuel de Isasi Isasmendi en las inmediaciones a la plaza de la Constituciâ”œâ”‚n. A la derecha, airoso frontispicio que indica la ubicaciâ”œâ”‚n del antiguo convento de Jerusalâ”œÂ®n de las hermanas Franciscanas Clarisas. Fuente visual: fot. Agustâ”œÂ¡n Lorente Bernal, en Marâ”œÂ¡a Pilar Poblador Muga, "La influencia del modernismo catalâ”œÃ­n en la arquitectura de Zaragoza", IFC, 2013.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65101800, -0.88220200, '0101000020E6100000C5E74EB0FF3AECBFBD8DCD8E54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29392351398.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29392351398.webp', 'https://www.flickr.com/photos/zaragozaantigua/29392351398/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25692, 'Aparcamiento de Miguel Salamero 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/Febrero 1974. Imagen capturada durante la ampliaciâ”œâ”‚n del aparcamiento de la plaza de Miguel Salamero en la zona de ingreso desde la nueva Vâ”œÂ¡a Imperial, trazada entre este espacio donde estuviera la derribada manzana de viviendas delimitada por la calle del Azoque y la iglesia de Santiago el Mayor, que al fondo ya muestra recrecida su torre derecha.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65228800, -0.88430800, '0101000020E6100000D9EA724A404CECBF60C9552C7ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14905237655.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14905237655.webp', 'https://www.flickr.com/photos/zaragozaantigua/14905237655/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25699, 'Calle Azoque 1976', 'Es setiembre, y ese aâ”œâ–’o la maâ”œâ–’ana refrescaba. Desde la plaza de Salamero, antigua de Santa Fe, una mirada por la calle Azoque hacia la plaza del Carmen, al fondo, cuyo entorno estaba mudando aceleradamente desde la operaciâ”œâ”‚n "Cuarteles", y el que fuera de artillerâ”œÂ¡a del Carmen fuera derribado y urbanizado luego con nuevos y altos bloques, un hotel, dos cines... La calle de la Vieja Guardia, de forma especial, estaba en plena ebulliciâ”œâ”‚n constructiva, en ambas aceras, llevâ”œÃ­ndose por delante, por aâ”œâ–’adidura, todas las casonas de siglos pasados, incluyendo la "Casa del Obispo". La higienizaciâ”œâ”‚n y modernizaciâ”œâ”‚n de la vieja ciudad marchaba viento en popa, al menos al mismo ritmo que el crecimiento de beneficios de los emprendedores inmobiliarios implicados Fuente visual: Archivo Pâ”œâ•‘blico Municipal, Gerardo Sancho Ramo.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65203200, -0.88420600, '0101000020E6100000CAA99D616A4BECBF05F9D9C875D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19087800601.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19087800601.webp', 'https://www.flickr.com/photos/zaragozaantigua/19087800601/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25268, 'Pl. de la Constituciâ”œâ”‚n 1902', 'Fuente de la Princesa, o Neptuno. Fuente visual: Ignacio Coyne, Archivo Coyne, AHPZ', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.65214400, -0.88088500, '0101000020E6100000C72E51BD3530ECBF2D24607479D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14699563488.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14699563488.webp', 'https://www.flickr.com/photos/zaragozaantigua/14699563488/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25704, 'Calle Azoque 1976', 'Desde la plaza de Nâ”¬Â¬ Sâ”¬Â¬ del Carmen, una vista de la bulliciosa callle Azoque. A la izquierda, entrada al cine "Fleta", que en esos momentos proyectaba "La batalla de Midway" con el novedoso sistema "Sensurround", un apabullante vibrador sonoro que dejaba temblando a los cines, y a sus espectadores. Al fondo, la plaza de Salamero, antigua de Santa Fe. A la derecha, la manzana parcialmente pendiente de construcciâ”œâ”‚n en la esquina entre la antigua calleja de San Jerâ”œâ”‚nimo con la calle de Câ”œÃ­diz. Fuente: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65121300, -0.88458200, '0101000020E6100000302B14E97E4EECBF72DD94F25AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23699796369.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23699796369.webp', 'https://www.flickr.com/photos/zaragozaantigua/23699796369/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25705, 'Plaza de Salamero 1976', 'Imagen de la plaza de Salamero, antigua de la Santa Fe, cuando sobre la original calle Azoque estaba emergiendo la estructura de acero, cemento y cristal del moderno "Edificio Residencial-Comercial Salamero", una de las cimas de la nueva Zaragoza, en casi todas sus contrastadas acepciones. Al fondo, a la derecha, la calle Valenzuela, y la reciente sede del Banco de Aragâ”œâ”‚n, con su sirena-reloj semoviente. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65246300, -0.88418500, '0101000020E6100000ECA353573E4BECBFCE6C57E883D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23800373339.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23800373339.webp', 'https://www.flickr.com/photos/zaragozaantigua/23800373339/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25708, 'Calle Cinco de Marzo 1923', 'Calle del Cinco de Marzo. Al fondo, plaza de Salamero e iglesia de Santiago. Fuente: Foto Jesâ”œâ•‘s Cormâ”œÃ­n. AMZ.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.65200600, -0.88345600, '0101000020E61000002A8F6E844545ECBFDC65BFEE74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24289293743.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24289293743.webp', 'https://www.flickr.com/photos/zaragozaantigua/24289293743/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25712, 'Plaza de Salamero 1974', 'Imagen del derribo del antiguo nâ”¬â•‘ 2 (*) de la calle del 5 de marzo, redenominada "Requetâ”œÂ® Aragonâ”œÂ®s" por el componente carlista del râ”œÂ®gimen franquista, y que tuvo que esperar hasta la recuperaciâ”œâ”‚n de la democracia municipal, en 1979, para recuperar su nombre. Este edificio era esquinero a la plaza de Salamero, antigua de Santa Fe, desde donde se ha capturado la imagen. Posiblemente diseâ”œâ–’ado por Fernando de Yarza en 1905, fue uno de los mâ”œâ•‘ltiples ejemplos del trato dado al patrimonio urbanâ”œÂ¡stico de la ciudad en los convulsos aâ”œâ–’os 70 del pasado siglo. (*) Posteriormente, la numeraciâ”œâ”‚n de la calle fue "traslocada" de forma radical: pares e impares se cambiaron de acera, y comenzaron desde el paseo de la Independencia, cosa que antes hacâ”œÂ¡an desde la plaza de Salamero. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal Zaragoza.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65205800, -0.88375400, '0101000020E6100000A3B1F677B647ECBF2E8CF4A276D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26435116022.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26435116022.webp', 'https://www.flickr.com/photos/zaragozaantigua/26435116022/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25715, 'Plaza de Salamero 1974', 'Imagen capturada, posiblemente, desde la recrecida torre sur de la iglesia parroquial de Santiago el Mayor, y centrada en las obras de construcciâ”œâ”‚n de la singular y gran torre de oficinas comerciales y viviendas de la plaza de Salamero, antigua de Santa Fe. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65269900, -0.88426900, '0101000020E610000062BB7B80EE4BECBFE2900DA48BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33838883892.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33838883892.webp', 'https://www.flickr.com/photos/zaragozaantigua/33838883892/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25716, 'Pl. de Salamero 1929', 'Imagen capturada desde cierta altura en la plaza de Salamero (antigua de Santa Fe), y centrada en la fachada que a ella ofrecâ”œÂ¡a el tramo de la calle de Azoque, desde la calle de Telesforo Peromarta (a la derecha, fuera de plano), y hasta la calle de la Biblioteca (hacia a la izquierda, lo mismo). Ya en esta â”œÂ®poca se especulaba con la posibilidad de embellecer la ciudad eliminando rincones provincianos y antiestâ”œÂ®ticos, y este parecâ”œÂ¡a ser uno de ellos. Unas dâ”œÂ®cadas despuâ”œÂ®s, esta manzana fue derribada para dar paso a un necesario vial de gran capacidad para el trâ”œÃ­fico rodado, y espacio a un singular megabloque de oficinas comerciales. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65242900, -0.88396100, '0101000020E610000006103E946849ECBF22FB20CB82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35182409746.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35182409746.webp', 'https://www.flickr.com/photos/zaragozaantigua/35182409746/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25717, 'Calle de Câ”œÃ­diz 1911', 'Imagen capturada en la calle de Câ”œÃ­diz durante las tareas de extinciâ”œâ”‚n del incendio que el 19 de noviembre de ese aâ”œâ–’o asolâ”œâ”‚ la droguerâ”œÂ¡a y ferreterâ”œÂ¡a del Carmen, cuyo titular era Enrique Lamana, sita en el local comercial del inmueble del nâ”¬â•‘ 5 de esa calle, frente al convento de las Recogidas. En la fotografâ”œÂ¡a aparecen guardias de seguridad y elementos del arma de Artillerâ”œÂ¡a y de Ingenieros del cercano cuartel del Carmen, que reforzaron a la brigada municipal de bomberos. Entre el mojado adoquinado, vâ”œÂ¡as de la tranviaria lâ”œÂ¡nea de Madrid que hacia la izquierda conducen a la plaza del Pueblo. Al fondo y a la izquierda, tambiâ”œÂ®n, balcones del inmueble del nâ”¬â•‘ 106 de la calle del Azoque.', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.65108600, -0.88425900, '0101000020E61000007F32C687D94BECBF15713AC956D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50133110698.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50133110698.webp', 'https://www.flickr.com/photos/zaragozaantigua/50133110698/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
